// Compose 5-layer AI prompt from tenant configuration
const config = $input.first().json;

// Layer 1: Base Product Prompt (shared across all tenants)
const basePrompt = `Você é um assistente virtual para consultório de saúde. Você é educado, profissional, acolhedor e eficiente. Responda sempre em português brasileiro.

══════════════════════════════════════
📋 PROTOCOLOS GERAIS
══════════════════════════════════════
1. Respostas breves e diretas para WhatsApp (máximo 4-5 linhas por mensagem)
2. Use emojis com moderação para melhorar legibilidade
3. Sempre confirme dados antes de executar ações (agendar, cancelar)
4. NUNCA invente informações médicas - quando não souber, direcione ao profissional
5. Mantenha sigilo sobre dados de outros pacientes
6. Se não encontrar o paciente no sistema, trate como novo paciente
7. Não seja repetitiva
8. Mensagens de áudio são automaticamente transcritas para texto`;

// Layer 2: Clinic Context
const clinicContext = config.organization_name ? `

══════════════════════════════════════
🏥 INFORMAÇÕES DO CONSULTÓRIO
══════════════════════════════════════
- Clínica: ${config.organization_name}
- Endereço: ${config.organization_address || 'Não informado'}
- Telefone: ${config.organization_phone || 'Não informado'}
- Horário: ${JSON.stringify(config.organization_hours) || 'Consulte o consultório'}
- Instagram: ${config.organization_instagram ? '@' + config.organization_instagram : 'Não informado'}` : '';

// Layer 3: Professional Context
const professionalContext = `

══════════════════════════════════════
👨‍⚕️ PROFISSIONAL
══════════════════════════════════════
- Nome: ${config.full_name || config.nome || 'Profissional'}
- Especialidades: ${Array.isArray(config.specialties) ? config.specialties.join(', ') : (config.specialties || 'Geral')}
- Registro: ${config.credential_type || ''} ${config.credential_number || 'N/A'}`;

// Layer 4: Assistant Persona (from prompt_config JSON)
const promptConfig = config.prompt_config || {};
const assistantName = config.assistant_persona_name || 'Assistente Virtual';
const assistantTone = config.assistant_tone || 'profissional e acolhedor';

const personaContext = `

══════════════════════════════════════
🤖 SUA IDENTIDADE
══════════════════════════════════════
Você é ${assistantName}, assistente virtual deste consultório.
Personalidade: ${assistantTone}`;

// Layer 5: Service Context & Tools
const toolsContext = `

══════════════════════════════════════
🛠️ FERRAMENTAS DISPONÍVEIS
══════════════════════════════════════
Use as ferramentas disponíveis para:
- Buscar dados de pacientes
- Verificar horários disponíveis
- Agendar consultas
- Consultar agendamentos
- Gerenciar informações

Sempre confirme os dados antes de executar ações.`;

// Compose final prompt
const fullPrompt = basePrompt + clinicContext + professionalContext + personaContext + toolsContext + `

CONTEXTO DA BASE DE CONHECIMENTO:
{{ $json.rag_context }}

MENSAGEM DO USUÁRIO:
Perfil WhatsApp: {{ $('Validar Dados da Mensagem').first().json.sender_name }}
Telefone WhatsApp: {{ $('Validar Dados da Mensagem').first().json.sender_phone }}
Tipo de mensagem: {{ $('Validar Dados da Mensagem').first().json.message_type }}
Texto enviado: {{ $('Validar Dados da Mensagem').first().json.message_text }}`;

return [{ json: { 
    full_prompt: fullPrompt,
    professional_id: config.professional_id,
    tenant_code: config.tenant_code,
    schema_name: config.schema_name,
    whatsapp_instance_id: config.whatsapp_instance_id
}}];

const output = `✨ Conversa reiniciada com sucesso!

Seu histórico de conversa foi limpo e estou disponível para um novo atendimento.

Como posso ajudar você hoje? 😊`;

return [{ json: { output } }];

// Recebe o texto de entrada
const texto = $input.first().json.output;

// Divide o texto apenas pela sequência de barra invertida dupla (\n\n)
const itens = texto.split(/\n\n/);

// Retorna cada item como um objeto separado, filtrando itens vazios
return itens
  .filter(item => item.trim() !== "")
  .map(item => ({ item }));

// Extrair dados da mensagem recebida via API Oficial do WhatsApp (Meta Cloud API)
const body = $input.first().json.body || $input.first().json;

// Validar que é um webhook do WhatsApp Business
if (body.object !== 'whatsapp_business_account') {
  return [];
}

// Extrair a primeira entrada e mudança
const entry = (body.entry || [])[0];
if (!entry) return [];

const change = (entry.changes || [])[0];
if (!change || change.field !== 'messages') return [];

const value = change.value || {};
const metadata = value.metadata || {};

// Extrair mensagem (ignorar status/delivery receipts)
const messages = value.messages || [];
if (messages.length === 0) return [];

const msg = messages[0];
const contacts = value.contacts || [];
const contact = contacts[0] || {};

// Dados do remetente
const message_from = msg.from || '';
const message_from_profile_name = contact.profile?.name || '';
const message_id = msg.id || '';
const whatsapp_phone_number = metadata.display_phone_number || '';
const whatsapp_phone_number_id = metadata.phone_number_id || '';

// Determinar tipo da mensagem
let message_type = 'text';
let message_content = '';
let media_mimetype = '';
let media_caption = '';
let media_id = '';

if (msg.type === 'audio') {
  message_type = 'audio';
  media_mimetype = msg.audio?.mime_type || 'audio/ogg';
  media_id = msg.audio?.id || '';
} else if (msg.type === 'image') {
  message_type = 'image';
  media_mimetype = msg.image?.mime_type || 'image/jpeg';
  media_caption = msg.image?.caption || '';
  media_id = msg.image?.id || '';
} else if (msg.type === 'text') {
  message_content = msg.text?.body || '';
} else if (msg.type === 'interactive') {
  message_content = msg.interactive?.button_reply?.title || msg.interactive?.list_reply?.title || '';
} else if (msg.type === 'button') {
  message_content = msg.button?.text || '';
} else {
  // Tipo não suportado
  return [];
}

// Detectar comandos de reset da conversa
const resetCommands = ['/limpar', '/reset', '/reiniciar', '/nova conversa', '/novo', 'nova conversa', 'limpar conversa', '#reiniciar', '#reset', '#limpar', 'reiniciar conversa', 'recomeçar conversa', 'recomecar conversa', 'começar denovo', 'comecar denovo'];

const normalizedContent = message_content.trim().toLowerCase();
if (resetCommands.includes(normalizedContent)) {
  message_type = 'reset';
}

// Montar sessionId: telefone do assistente + telefone do usuário
const session_id = whatsapp_phone_number + '|' + message_from;

return [{
  json: {
    message_type,
    message_content,
    media_mimetype,
    media_caption,
    media_id,
    message_from,
    message_from_profile_name,
    message_id,
    session_id, 
    whatsapp_phone_number,
    whatsapp_phone_number_id,
    raw_message: msg
  }
}];

// Preparar texto transcrito do áudio para o agente IA
const transcription = $input.first().json.text || '';
const originalData = $('Mensagem Recebida').first().json;

const transcription_text = (transcription && transcription.trim()) 
      ? transcription.trim()
      : '[Áudio recebido mas não foi possível transcrever. Por favor, envie em texto.]'

return [{
  json: {
    ...originalData,
    message_type: 'audio',
    chat_input: `[Mensagem de áudio transcrita]: ${transcription_text}`,
    original_transcription: transcription_text
  }
}];

// Restaurar dados originais da mensagem recebida
const originalData = $('Mensagem Recebida').first().json;

// Unificar todas as mensagens (texto, áudio, imagem) para o agente IA
const item = $input.first().json;

return [{
  json: {
    ...item,
    ...originalData
  }
}];

// Preparar mensagem de texto para o agente IA
const originalData = $('Mensagem Recebida').first().json;
const messageContent = originalData.message_content

return [{
  json: {
    ...originalData,
    chat_input: messageContent,
    message_type: 'text'
  }
}];

// Restaurar dados originais da mensagem recebida
const originalData = $('Mensagem Recebida').first().json;

// Mensagem de reset
const mensagemReset = $('Mensagem de Reset').first().json;

return [{
  json: {
    ...mensagemReset,
    ...originalData
  }
}];
